module sd_card_controller(  
    input wire clk,  
    input wire rst,  
    input wire cmd,  
    input wire [7:0] data_in,  
    output reg [7:0] data_out  
);  
    reg [7:0] invalid_data;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            invalid_data <= 8'b0;  
            data_out <= 8'b0;  
        end else begin  
            if (cmd == 1'b1) begin  // Write operation  
                invalid_data <= data_in;  
            end else begin  // Read operation  
                data_out <= invalid_data;  
            end  
        end  
    end  
endmodule
